mapper.select:
SELECT
a.id, a.article_name, a.article_outline, a.story_background, a.theme, a.additional_characteristics, a.voice_tone, a.voice_link, a.voice_file_path,
a.video_link, a.video_file_path, a.publish_status, a.total_word_count_estimate, a.chapter_word_count_estimate, a.create_user_id, a.create_time, a.update_time,
u.user_name AS create_user_name
FROM article a
LEFT JOIN user_info u ON a.create_user_id = u.id AND u.res_state = 1

    a.res_state = 1

        AND a.create_user_id = #{scopedCreateUserId,jdbcType=BIGINT}


        AND a.article_name LIKE CONCAT('%', #{articleName,jdbcType=VARCHAR}, '%')


        AND a.voice_tone = #{voiceTone,jdbcType=VARCHAR}


        AND a.publish_status = #{publishStatus,jdbcType=SMALLINT}


        AND a.theme = #{theme,jdbcType=VARCHAR}


ORDER BY a.create_time DESC

mapper.update:
UPDATE article
article_name = #{articleName,jdbcType=VARCHAR}, article_outline = #{articleOutline,jdbcType=VARCHAR}, story_background = #{storyBackground,jdbcType=VARCHAR}, image_desc = #{imageDesc,jdbcType=VARCHAR}, theme = #{theme,jdbcType=VARCHAR}, additional_characteristics = #{additionalCharacteristics,jdbcType=VARCHAR}, voice_tone = #{voiceTone,jdbcType=VARCHAR}, voice_link = #{voiceLink,jdbcType=VARCHAR}, voice_file_path = #{voiceFilePath,jdbcType=VARCHAR}, video_link = #{videoLink,jdbcType=VARCHAR}, video_file_path = #{videoFilePath,jdbcType=VARCHAR}, publish_status = #{publishStatus,jdbcType=SMALLINT}, total_word_count_estimate = #{totalWordCountEstimate,jdbcType=INTEGER}, chapter_word_count_estimate = #{chapterWordCountEstimate,jdbcType=INTEGER}, story_complete = #{storyComplete,jdbcType=BOOLEAN}, res_state = #{resState,jdbcType=INTEGER}, response_id = #{responseId,jdbcType=VARCHAR}, update_time = #{updateTime,jdbcType=TIMESTAMP}
WHERE id = #{id,jdbcType=BIGINT}

UPDATE article
SET res_state = 0, update_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}

UPDATE article
SET publish_status = #{publishStatus,jdbcType=SMALLINT}, update_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}

UPDATE article
SET response_id = #{responseId,jdbcType=VARCHAR}
WHERE id = #{id,jdbcType=BIGINT}
AND res_state = 1
